values
('Cosmic Core', 'cosmic-core', 'The foundational Cosmic Card deck for clarity, courage, trust, and alignment.', 'decks/cosmic-core/cover', 'cosmic-classic', true, false, 1),
('Self-Love', 'self-love', 'A compassionate deck for tenderness, confidence, and self-return.', 'decks/self-love/cover', 'rose-glow', true, false, 2),
('Healing', 'healing', 'Gentle cards for emotional repair, integration, and steadier healing seasons.', 'decks/healing/cover', 'silver-moon', true, false, 3),
('Abundance', 'abundance', 'A deck for grounded prosperity, receiving, and expansive support.', 'decks/abundance/cover', 'golden-harvest', true, true, 4),
('Love & Relationships', 'love-relationships', 'Reflections for reciprocal connection, emotional clarity, and relational warmth.', 'decks/love-relationships/cover', 'heart-current', true, true, 5),
('Career & Purpose', 'career-purpose', 'Focused guidance for meaningful work, leadership, and sustainable momentum.', 'decks/career-purpose/cover', 'aurora-work', true, true, 6),
('Inner Reset', 'inner-reset', 'A restorative deck for release, rest, and emotional reset.', 'decks/inner-reset/cover', 'midnight-bloom', true, true, 7)
on conflict (slug) do update
set
  name = excluded.name,
  description = excluded.description,
  cover_image_key = excluded.cover_image_key,
  theme_key = excluded.theme_key,
  is_active = excluded.is_active,
  is_premium = excluded.is_premium,
  sort_order = excluded.sort_order,
  updated_at = now();

update cards
set
  slug = slug || '-legacy-' || substr(id::text, 1, 8),
  card_no = card_no + 1000,
  is_active = false,
  updated_at = now()
