((select id from decks where slug = 'self-love'), 'sovereign-core', 336, 'Sovereign Core', 'Your power becomes clearer when it is no longer performing for approval. Own your pace, your voice, and your standards.', 'A rooted center helps you respond with intention instead of reflex. Move from steadiness and let that be enough.', 'inner-power', 'quiet confidence', 'inner-power/sovereign-core', true),
((select id from decks where slug = 'self-love'), 'sovereign-voice', 337, 'Sovereign Voice', 'The more grounded you are, the less explaining you need. Inner authority is built through self-trust, not control.', 'Your presence becomes more magnetic when it is not diluted by self-betrayal. For now, make one decision today from your most anchored self.', 'inner-power', 'grounded action', 'inner-power/sovereign-voice', true),
((select id from decks where slug = 'self-love'), 'sovereign-flame', 338, 'Sovereign Flame', 'You do not need to become louder to become more powerful. As you move through today, lead yourself with clarity before you lead the moment.', 'Inner power is the ability to remain connected to yourself while life keeps moving around you. If it feels supportive, choose the action that makes you feel more self-led.', 'inner-power', 'protection', 'inner-power/sovereign-flame', true),
((select id from decks where slug = 'self-love'), 'sovereign-center', 339, 'Sovereign Center', 'The strongest center is the one that stays connected to truth. For now, stand in what you know without making yourself hard to stay there.', 'The strength you are looking for may already exist in the decisions you keep avoiding. In this moment, own your voice without rushing to justify it.', 'inner-power', 'expansion', 'inner-power/sovereign-center', true),
((select id from decks where slug = 'self-love'), 'sovereign-authority', 340, 'Sovereign Authority', 'Power feels different when it is rooted instead of reactive. Own your pace, your voice, and your standards.', 'The body recognizes real power by how safe it feels to inhabit your own truth. Trust your ability to hold your own energy with care.', 'inner-power', 'inner fire', 'inner-power/sovereign-authority', true),
((select id from decks where slug = 'self-love'), 'sovereign-pulse', 341, 'Sovereign Pulse', 'The more grounded you are, the less explaining you need. Your energy sharpens when you stop handing your certainty away.', 'Confidence becomes sustainable when it is built on integrity rather than image. For now, protect your center before you manage the room.', 'inner-power', 'self-leadership', 'inner-power/sovereign-pulse', true),
((select id from decks where slug = 'self-love'), 'sovereign-strength', 342, 'Sovereign Strength', 'There is strength in choosing yourself without turning hard. As you move through today, lead yourself with clarity before you lead the moment.', 'Self-leadership grows through clear boundaries, honest choices, and emotional steadiness. If it feels supportive, let your standards reflect your actual worth.', 'inner-power', 'quiet confidence', 'inner-power/sovereign-strength', true),
((select id from decks where slug = 'self-love'), 'sovereign-current', 343, 'Sovereign Current', 'Real confidence often sounds quieter than insecurity expects. For now, stand in what you know without making yourself hard to stay there.', 'You carry more authority when your actions are no longer split by doubt and performance. In this moment, allow calm confidence to shape your next response.', 'inner-power', 'grounded action', 'inner-power/sovereign-current', true),
((select id from decks where slug = 'self-love'), 'bright-core', 344, 'Bright Core', 'Your power becomes clearer when it is no longer performing for approval. Own your pace, your voice, and your standards.', 'A rooted center helps you respond with intention instead of reflex. Move from steadiness and let that be enough.', 'inner-power', 'protection', 'inner-power/bright-core', true),
((select id from decks where slug = 'self-love'), 'bright-voice', 345, 'Bright Voice', 'The more grounded you are, the less explaining you need. Inner authority is built through self-trust, not control.', 'Your presence becomes more magnetic when it is not diluted by self-betrayal. For now, make one decision today from your most anchored self.', 'inner-power', 'expansion', 'inner-power/bright-voice', true),
((select id from decks where slug = 'self-love'), 'bright-flame', 346, 'Bright Flame', 'You do not need to become louder to become more powerful. As you move through today, lead yourself with clarity before you lead the moment.', 'Inner power is the ability to remain connected to yourself while life keeps moving around you. If it feels supportive, choose the action that makes you feel more self-led.', 'inner-power', 'inner fire', 'inner-power/bright-flame', true),
((select id from decks where slug = 'self-love'), 'bright-center', 347, 'Bright Center', 'The strongest center is the one that stays connected to truth. For now, stand in what you know without making yourself hard to stay there.', 'The strength you are looking for may already exist in the decisions you keep avoiding. In this moment, own your voice without rushing to justify it.', 'inner-power', 'self-leadership', 'inner-power/bright-center', true),
